import time
from functools import wraps


_rate_limit_cache = {}


def rate_limit(max_calls, per_seconds=60):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = func.__name__
            now = time.time()

            if key not in _rate_limit_cache:
                _rate_limit_cache[key] = []

            _rate_limit_cache[key] = [
                t for t in _rate_limit_cache[key] if now - t < per_seconds
            ]

            if len(_rate_limit_cache[key]) >= max_calls:
                raise RuntimeError(f'Rate limit exceeded for {key}')

            _rate_limit_cache[key].append(now)
            return func(*args, **kwargs)

        return wrapper
    return decorator


